+  const fallbackInput = `${ipHint}|${userAgent}|${acceptLanguage}`;
+  if (!fallbackInput.trim()) return 'unknown';
+
+  let hash = 0x811c9dc5;
+  for (let i = 0; i < fallbackInput.length; i++) {
